import{_ as t,o as i,c as a,ag as o}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"Your First Invoice","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/first-invoice.md","filePath":"getting-started/first-invoice.md"}'),r={name:"getting-started/first-invoice.md"};function n(s,e,l,c,d,u){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="your-first-invoice" tabindex="-1">Your First Invoice <a class="header-anchor" href="#your-first-invoice" aria-label="Permalink to &quot;Your First Invoice&quot;">​</a></h1><p>This guide walks you through creating and sending your first invoice in MyCompanyDesk.</p><h2 id="before-you-start" tabindex="-1">Before you start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to &quot;Before you start&quot;">​</a></h2><p>Make sure you have:</p><ul><li><a href="/getting-started/company-setup">Set up your company information</a> (name, address, IBAN)</li><li>At least one customer to invoice (you can create one during the process)</li></ul><h2 id="create-an-invoice" tabindex="-1">Create an invoice <a class="header-anchor" href="#create-an-invoice" aria-label="Permalink to &quot;Create an invoice&quot;">​</a></h2><ol><li>Navigate to <strong>Invoices</strong> in the sidebar</li><li>Click the <strong>New Invoice</strong> button (or use the <strong>+</strong> floating button on mobile)</li><li>Fill in the invoice form:</li></ol><h3 id="select-a-customer" tabindex="-1">Select a customer <a class="header-anchor" href="#select-a-customer" aria-label="Permalink to &quot;Select a customer&quot;">​</a></h3><p>Start typing the customer name. If the customer exists, select them from the dropdown. If not, click <strong>Create new customer</strong> to add them inline.</p><h3 id="add-line-items" tabindex="-1">Add line items <a class="header-anchor" href="#add-line-items" aria-label="Permalink to &quot;Add line items&quot;">​</a></h3><p>Each line item has:</p><ul><li><strong>Description</strong> — What you&#39;re billing for</li><li><strong>Quantity</strong> — Number of units</li><li><strong>Unit price</strong> — Price per unit</li><li><strong>VAT rate</strong> — Applicable VAT percentage (0%, 9%, 21%, etc.)</li></ul><p>Click <strong>Add item</strong> to add more line items. The total is calculated automatically including VAT.</p><h3 id="set-invoice-details" tabindex="-1">Set invoice details <a class="header-anchor" href="#set-invoice-details" aria-label="Permalink to &quot;Set invoice details&quot;">​</a></h3><ul><li><strong>Invoice number</strong> — Auto-generated based on your numbering settings</li><li><strong>Invoice date</strong> — Defaults to today</li><li><strong>Due date</strong> — Calculated from your default payment terms (adjustable)</li><li><strong>Notes</strong> — Optional notes that appear on the invoice</li></ul><h3 id="save" tabindex="-1">Save <a class="header-anchor" href="#save" aria-label="Permalink to &quot;Save&quot;">​</a></h3><p>Click <strong>Save</strong> to create the invoice as a <strong>draft</strong>. You can still edit everything before sending.</p><h2 id="preview-the-invoice" tabindex="-1">Preview the invoice <a class="header-anchor" href="#preview-the-invoice" aria-label="Permalink to &quot;Preview the invoice&quot;">​</a></h2><p>Before sending, preview how the PDF will look:</p><ol><li>Open the invoice detail page</li><li>Click <strong>Preview</strong> to see the generated PDF</li><li>Check that all information is correct — company details, customer info, line items, totals</li></ol><h2 id="send-the-invoice" tabindex="-1">Send the invoice <a class="header-anchor" href="#send-the-invoice" aria-label="Permalink to &quot;Send the invoice&quot;">​</a></h2><p>When you&#39;re ready to send:</p><ol><li>Click <strong>Send</strong> on the invoice detail page</li><li>Review the email that will be sent to your customer: <ul><li>Subject line (customizable)</li><li>Email body (based on your email template)</li><li>PDF attachment</li><li>Payment link (if enabled)</li></ul></li><li>Click <strong>Send</strong> to deliver the invoice</li></ol><p>The invoice status changes from <strong>Draft</strong> to <strong>Sent</strong>.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can customize your email templates in <strong>Settings &gt; Email</strong>. Templates support your branding and can be set per language.</p></div><h2 id="track-payment" tabindex="-1">Track payment <a class="header-anchor" href="#track-payment" aria-label="Permalink to &quot;Track payment&quot;">​</a></h2><p>Once sent, the invoice appears in your <strong>Sent</strong> or <strong>Overdue</strong> views. When the customer pays:</p><ul><li>If the customer pays via the <strong>payment link</strong>, the invoice is marked as paid automatically</li><li>For bank transfers, click <strong>Mark as Paid</strong> on the invoice to record the payment manually</li></ul><h2 id="invoice-statuses" tabindex="-1">Invoice statuses <a class="header-anchor" href="#invoice-statuses" aria-label="Permalink to &quot;Invoice statuses&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Description</th></tr></thead><tbody><tr><td><strong>Draft</strong></td><td>Created but not yet sent. Fully editable.</td></tr><tr><td><strong>Sent</strong></td><td>Delivered to the customer. Waiting for payment.</td></tr><tr><td><strong>Overdue</strong></td><td>Past the due date and still unpaid.</td></tr><tr><td><strong>Paid</strong></td><td>Payment received and confirmed.</td></tr><tr><td><strong>Cancelled</strong></td><td>Invoice was cancelled. No payment expected.</td></tr></tbody></table><h2 id="quick-add" tabindex="-1">Quick add <a class="header-anchor" href="#quick-add" aria-label="Permalink to &quot;Quick add&quot;">​</a></h2><p>For faster invoice creation, use <strong>Quick Add</strong>:</p><ol><li>Click the quick-add icon on the invoices list page</li><li>Select a customer</li><li>Add items (or use a saved template)</li><li>Save and optionally send immediately</li></ol><p>Quick Add is ideal for routine invoices where you bill similar items regularly.</p><h2 id="using-templates" tabindex="-1">Using templates <a class="header-anchor" href="#using-templates" aria-label="Permalink to &quot;Using templates&quot;">​</a></h2><p>Save time with invoice templates:</p><ol><li>Create an invoice with your commonly used line items</li><li>Click <strong>Save as Template</strong></li><li>Next time, start a new invoice from the template — all items are pre-filled</li></ol><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><p>Congratulations on sending your first invoice! Explore more features:</p><ul><li><a href="/features/expenses">Track your expenses</a></li><li><a href="/features/quotes">Create quotes</a> for potential work</li><li><a href="/features/recurring-invoices">Set up recurring invoices</a> for regular billing</li><li><a href="/features/reports">View reports</a> to understand your finances</li></ul>',40)])])}const g=t(r,[["render",n]]);export{m as __pageData,g as default};
